html:
{% set ns = namespace(counter=1) %}
{% set co = frappe.db.get_value("Bank Account", {"is_company_account": 1, "company": doc.company}, ["bank_account_no", "branch_code", "ifsc_code"], as_dict=1) %}
<style>
  body, html {
    font-family: "Courier New", Courier, monospace;
    font-size: 11px;
    background: #fff;
    color: #000;
    margin: 0;
    padding: 10px;
  }
  .neft-line {
    white-space: pre;
    line-height: 1.8;
    word-break: break-all;
  }
</style>

<div>
{# Company account - first line #}
{% if co %}
<div class="neft-line">{% if co.bank_account_no %}{{ co.bank_account_no }}{% endif %}{% if co.branch_code %}#{{ co.branch_code }}{% endif %}{% if co.ifsc_code %}#{{ co.ifsc_code }}{% endif %}{% if doc.date_of_cheque %}#{{ frappe.utils.formatdate(doc.date_of_cheque, "dd/MM/yyyy") }}{% endif %}{% if doc.cheque_amount %}#{{ "%.2f"|format(doc.cheque_amount) }}{% endif %}##NEFT{{ "%08d"|format(ns.counter) }}{% if doc.bank %}#{{ doc.bank }}{% endif %}#SUPPLIER PAYMENT</div>
{% set ns.counter = ns.counter + 1 %}
{% endif %}

{# Child table rows #}
{% for row in doc.supplier_details %}
<div class="neft-line">{% if row.account_no %}{{ row.account_no }}{% endif %}{% if row.branch_code %}#{{ row.branch_code }}{% endif %}{% if row.ifsc_code %}#{{ row.ifsc_code }}{% endif %}{% if doc.date_of_cheque %}#{{ frappe.utils.formatdate(doc.date_of_cheque, "dd/MM/yyyy") }}{% endif %}{% if row.allocated_amount %}#{{ "%.2f"|format(row.allocated_amount) }}{% endif %}##NEFT{{ "%08d"|format(ns.counter) }}{% if row.account %}#{{ row.account }}{% endif %}{% if row.bill_no %}# BILL NO {{ row.bill_no }}{% endif %}</div>
{% set ns.counter = ns.counter + 1 %}
{% endfor %}
</div>
